For each order, evaluate insertion cost into all existing routes plus a new empty route, select the feasible insertion with minimal marginal cost increase, and commit it while preserving all orders.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	nOrders := len(oris)
	existingLimit := dispatch.AssignsLen
	if existingLimit == 0 {
		existingLimit = 1
	}
	type candidate struct {
		assignIdx   int
		costDelta   float64
		oldCost     float64
		newCost     float64
		insertValid bool
	}
	for jj := 0; jj < nOrders; jj++ {
		orderId := total_ship + jj
		bestCand := candidate{assignIdx: -1, costDelta: 1e100, oldCost: 0, newCost: 0, insertValid: false}
		for idxTry := 0; idxTry <= dispatch.AssignsLen; idxTry++ {
			if idxTry >= MAXASSIGNS {
				continue
			}
			assignPtr := &dispatch.Assigns[idxTry]
			savedStation := assignPtr.StationCurrent
			savedCost := assignPtr.Cost
			ok := assignPtr.AddShip(orderId, oris[jj], dess[jj])
			if ok {
				assignPtr.GenRoute()
				newCost := assignPtr.Cost
				delta := newCost - savedCost
				if newCost >= 0 && delta < bestCand.costDelta {
					bestCand.assignIdx = idxTry
					bestCand.costDelta = delta
					bestCand.oldCost = savedCost
					bestCand.newCost = newCost
					bestCand.insertValid = true
				}
				assignPtr.RemoveShip(orderId)
				assignPtr.StationCurrent = savedStation
				assignPtr.Cost = savedCost
				assignPtr.GenRoute()
			}
		}
		if bestCand.insertValid {
			targetIdx := bestCand.assignIdx
			if targetIdx == dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.AssignsLen++
			}
			dispatch.Assigns[targetIdx].AddShip(orderId, oris[jj], dess[jj])
			dispatch.Assigns[targetIdx].GenRoute()
		} else {
			fallbackOk := false
			for fbIdx := 0; fbIdx <= dispatch.AssignsLen && fbIdx < MAXASSIGNS; fbIdx++ {
				assignPtr := &dispatch.Assigns[fbIdx]
				savedStation := assignPtr.StationCurrent
				savedCost := assignPtr.Cost
				if assignPtr.AddShip(orderId, oris[jj], dess[jj]) {
					assignPtr.GenRoute()
					if assignPtr.Cost >= 0 {
						if fbIdx == dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
						fallbackOk = true
						break
					} else {
						assignPtr.RemoveShip(orderId)
						assignPtr.StationCurrent = savedStation
						assignPtr.Cost = savedCost
						assignPtr.GenRoute()
					}
				}
			}
			if !fallbackOk {
				newIdx := dispatch.AssignsLen
				if newIdx < MAXASSIGNS {
					dispatch.Assigns[newIdx].AddShip(orderId, oris[jj], dess[jj])
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						dispatch.Assigns[newIdx].RemoveShip(orderId)
						dispatch.Assigns[newIdx].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

